import{_ as s,g as t,h as n,S as e}from"./chunks/vitepress-theme-teek.B9ybUUp0.js";const d=JSON.parse('{"title":"放弃增长执念，为什么“小而美”才是可持续之路","description":"摘要总结：在很长一段时间里，科技互联网行业的叙事都被“不惜一切代价实现超线性增长”所主导。仿佛只有拿到巨额融资、疯狂招人、成为估值破百亿的庞然大物，才算得上是成功的创业。然而，读完萨希尔·拉文吉亚的《小而美：持续盈利的经营法则》后，笔者获得了一种截然不同的商业视角：企业存在的首要目的不是为了融资和扩张，而是为了通过解决问题来获得持续的盈利。 本文结合书中的核心论点与自身的研发视角，把将这本书背后的经营逻辑与产品哲学梳理为几个核心层面的思考。","frontmatter":{"date":"2025-11-24T21:50:00.000Z","title":"放弃增长执念，为什么“小而美”才是可持续之路","description":"摘要总结：在很长一段时间里，科技互联网行业的叙事都被“不惜一切代价实现超线性增长”所主导。仿佛只有拿到巨额融资、疯狂招人、成为估值破百亿的庞然大物，才算得上是成功的创业。然而，读完萨希尔·拉文吉亚的《小而美：持续盈利的经营法则》后，笔者获得了一种截然不同的商业视角：企业存在的首要目的不是为了融资和扩张，而是为了通过解决问题来获得持续的盈利。 本文结合书中的核心论点与自身的研发视角，把将这本书背后的经营逻辑与产品哲学梳理为几个核心层面的思考。","coverImg":"https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/cover/product_sense_bg.png","permalink":"/product-sense/small-rule-learn","categories":["产品 Sense"],"tags":["产品 Sense","商业化"]},"headers":[],"relativePath":"10.产品 Sense/04.产品创造与商业化/30.《小而美：持续盈利的经营法则》读后感.md","filePath":"10.产品 Sense/04.产品创造与商业化/30.《小而美：持续盈利的经营法则》读后感.md"}'),r={name:"10.产品 Sense/04.产品创造与商业化/30.《小而美：持续盈利的经营法则》读后感.md"};function o(i,a,p,l,c,m){return n(),t("div",null,[...a[0]||(a[0]=[e("",24)])])}const g=s(r,[["render",o]]);export{d as __pageData,g as default};
